/********************************************************
 AD変換デバイスドライバ
 *******************************************************/
#include <avr/io.h>
#include "input_adc.h"

/*****************************************
 define
*****************************************/
/* ADC制御レジスタ値 */

/* REFS1,REFS0 : 基準電圧選択 00(AREFピンの外部基準電圧) */
/* ADLAR : 左揃え選択 1(左揃え) */
/* MUX3～0 : A/D チャネル選択 0000(ADC0) */
#define ADC_ADMUX_INIT      (_BV(ADLAR))

#define ADC_ADMUX_MUX_BIT   (_BV(MUX3) | _BV(MUX2) | _BV(MUX1) | _BV(MUX0))

/* ADEN : A/D 許可 1(許可) */
/* ADSC : A/D 変換が始まってしまうため、開始時に設定 */
/* ADATE : A/D 変換自動起動許可 0(禁止) */
/* ADIF : A/D 変換完了割り込みフラグ 0(解除) */
/* ADIE : A/D 変換完了割り込み許可 0(禁止) */
/* ADPS2～0 : A/D 変換クロック選択 111(128分周) */
#define ADC_ADCSRA_INIT     (_BV(ADEN) | _BV(ADPS2) | _BV(ADPS1) | _BV(ADPS0))
/* ADSC : 1 (A/D 変換開始) */
/* ADIF : A/D 変換完了割り込みフラグ 1(1書き込みで解除) */
#define ADC_ADCSRA_START    (ADC_ADCSRA_INIT | _BV(ADSC) | _BV(ADIF))

/* ADC5D : ADC5ﾃﾞｼﾞﾀﾙ入力禁止 (ADC5 Digital Input Disable) 1(禁止) */
/* ADC4D : ADC4ﾃﾞｼﾞﾀﾙ入力禁止 (ADC4 Digital Input Disable) 1(禁止) */
#define ADC_DIDR0_INIT      (_BV(ADC5D) | _BV(ADC4D))


/* ADキー用定義 */
#define ADC_ADKEY_CHATTERING_COUNT  (1)             /* チャタリング除去 確認回数 */
#define ADC_ADKEY_CONTINUE_COUNT    (3000 / 2)      /* キー長押し認識時間(ms/論理Ch数) */
#define ADC_BANK_SIZE               (4)             /* AD変換結果保持バッファバンク数 */

/* ADキー閾値 */
#define ADC_ADKEY_LEVEL0            (32)
#define ADC_ADKEY_LEVEL1            (96)
#define ADC_ADKEY_LEVEL2            (160)
#define ADC_ADKEY_LEVEL3            (224)

/* 可変抵抗 最大・最小値 */
#define ADC_VR_VAL_MAX              (255)
#define ADC_VR_VAL_MIN              (80)

/*****************************************
 関数プロトタイプ宣言
*****************************************/
/*  ADC driver (middle level) */
static void adc_decode(void);
static void adc_decode_adkey(AdcChannelType channel);
static void adc_decode_vr(AdcChannelType channel);
static void adc_set_nextch(void);

/*  ADC driver (low level) */
static void adc_read_data(void);
static void adc_set_nextbank(void);
static unsigned char adc_get_average(AdcChannelType channel);

/*****************************************
 定数定義
*****************************************/
/* 論理チャネルと使用機能の引き当て */
static void (* const adc_decode_func[AdcChMax])(AdcChannelType channel) = {
    &adc_decode_adkey,  /* Ch0:ADキー */
    &adc_decode_vr,     /* Ch1:可変抵抗 */
};

/* 論理チャネルと物理チャネルの引き当て */
static const unsigned char adc_phych[AdcChMax] = {
    5,  /* Ch0:ADキー */
    4   /* Ch1:可変抵抗 */
};
/*****************************************
 変数宣言
*****************************************/
static unsigned char adc_buffer[AdcChMax][ADC_BANK_SIZE];   /* AD 出力バッファ */
static unsigned char adc_channel;                           /* AD 論理チャネル */
static unsigned char adc_bank;                              /* AD結果出力バッファバンクID( 0 ～ 1 ) */
static AdcAdkeyCodeType adc_adkey_confirm;                  /* 出力用ADキー 確定情報 */
static AdcAdkeyEventType adc_event_adkey;                   /* 出力用ADキー変化イベント */

static AdcAdkeyCodeType adc_adkey_pending;                  /* ADキー チャタリング除去中情報 */
static unsigned char adc_adkey_pending_count;               /* ADキー チャタリング検出カウント */
static unsigned short adc_adkey_continue_time;              /* ADキー 長押しイベント検出カウント */

static unsigned char adc_vr_value;                          /* 出力用VR電圧 */

/*****************************************
 AD コンバータ初期設定
*****************************************/
void adc_init(void)
{
    unsigned char adch;
    unsigned char bank;

    for(adch = 0; adch < AdcChMax; adch++){
        for(bank = 0; bank < ADC_BANK_SIZE; bank++){
            adc_buffer[adch][bank] = 0;
        }
    }
    adc_channel = (AdcChMax - 1);
    adc_bank = 0;
    adc_adkey_confirm = ADC_ADKEY_INVALID;
    adc_event_adkey = AdcAdkeyEvtNone;
    adc_adkey_pending = ADC_ADKEY_INVALID;
    adc_adkey_pending_count = 0;
    adc_adkey_continue_time = 0;
    adc_vr_value = 0;

    ADMUX = ADC_ADMUX_INIT;
    ADCSRA = ADC_ADCSRA_INIT;
    DIDR0 = ADC_DIDR0_INIT;
}

/*****************************************
 AD 変換開始
*****************************************/
void adc_start(void)
{
    unsigned char admux_buf;

    /* AD変換入力端子設定(物理チャネル指定) */
    admux_buf = ADMUX & (~ADC_ADMUX_MUX_BIT);
    admux_buf |= adc_phych[adc_channel];
    ADMUX = admux_buf;

    /* AD変換開始 */
    ADCSRA = ADC_ADCSRA_START;
}

/*****************************************
 AD コンバート処理
*****************************************/
void adc_convert(void)
{
    if ((ADCSRA & _BV(ADSC)) != 0x00) {
        /* AD 変換中であれば、結果の読み出しをしない */
        return;
    }

    /* AD 変換結果をバッファに保存 */
    adc_read_data();
    /* デコード処理 */
    adc_decode();
    /* 次回AD変換対象論理チャネル更新 */
    adc_set_nextch();
    /* AD変換開始 */
    adc_start();
}


/*****************************************
 可変抵抗電圧取得
*****************************************/
unsigned char adc_get_vr(void)
{
    return adc_vr_value;
}

/*****************************************
 可変抵抗電圧(正規化)取得
*****************************************/
unsigned char adc_get_vr_nrm(void)
{
    unsigned short vr_value;

    vr_value = adc_vr_value;
    if( vr_value < adc_vr_val_min){
        vr_value = adc_vr_val_min;
    }
    if( vr_value > adc_vr_val_max){
        vr_value = adc_vr_val_max;
    }
    return (unsigned char)((vr_value-adc_vr_val_min)*255/(adc_vr_val_max-adc_vr_val_min));
}

/*****************************************
 AD キー変化イベント有無の確認
*****************************************/
AdcAdkeyEventType adc_chk_event_adkey(void)
{
    return adc_event_adkey;
}

/*****************************************
 AD キー変化イベントのクリア
*****************************************/
void adc_clr_event_adkey(void)
{
    adc_event_adkey = AdcAdkeyEvtNone;
}

/*****************************************
 AD キーコード取得
*****************************************/
AdcAdkeyCodeType adc_get_adkeycode(void)
{
    return adc_adkey_confirm;
}

/*****************************************
 ADC 結果取得
*****************************************/
unsigned char adc_get_value(AdcChannelType channel)
{
    return adc_get_average(channel);
}

/*****************************************
 AD データ読み出し
*****************************************/
static void adc_read_data(void)
{
    adc_buffer[adc_channel][adc_bank] = ADCH;
}

/*****************************************
 AD データ読み出し
*****************************************/
static void adc_decode(void)
{
    AdcChannelType channel;

    channel = adc_channel;
    adc_decode_func[channel](channel);
}

/*****************************************
 AD キーデコード
*****************************************/
static void adc_decode_adkey(AdcChannelType channel)
{
    unsigned char ad_key_level;
    AdcAdkeyCodeType keycode_latest;
    unsigned char count;

    ad_key_level = adc_buffer[channel][adc_bank];
    if (ADC_ADKEY_LEVEL3 <= ad_key_level) {
        keycode_latest = ADC_ADKEY_OFF;              /*  キーオフ */
    } else if (ADC_ADKEY_LEVEL2 < ad_key_level) {
        keycode_latest = ADC_ADKEY_3;                /*  キー3 オン */
    } else if (ADC_ADKEY_LEVEL1 < ad_key_level) {
        keycode_latest = ADC_ADKEY_2;                /*  キー2 オン */
    } else if (ADC_ADKEY_LEVEL0 < ad_key_level) {
        keycode_latest = ADC_ADKEY_1;                /*  キー1 オン */
    } else {
        keycode_latest = ADC_ADKEY_0;                /*  キー0 オン */
    }

    /*  チャタリング除去処理 */
    /* キー変化なしのまま規定時間経過したらキーの状態を確定する */
    if (adc_adkey_pending != keycode_latest) {  /* キー変化あり */
        /* チャタリング除去処理開始 */
        adc_adkey_pending = keycode_latest;
        adc_adkey_pending_count = ADC_ADKEY_CHATTERING_COUNT;
    }else{                                      /* キー変化なし */
        count = adc_adkey_pending_count;

        if (count > 0) { /*  チャタリング除去中 */
            /*  チャタリング検出カウンタを更新 */
            count--;
            adc_adkey_pending_count = count;

            if (count == 0) {       /*  チャタリング検出カウント終了 */
                /*  確定値保存 */
                adc_adkey_confirm = adc_adkey_pending;
                adc_event_adkey = AdcAdkeyEvtChange;
				if (adc_adkey_confirm != ADC_ADKEY_OFF) {
					/* ボタンを押しているなら長押し判定開始 */
	                adc_adkey_continue_time = ADC_ADKEY_CONTINUE_COUNT;
				}else{
					/* ボタンを離したなら長押し判定キャンセル */
					adc_adkey_continue_time = 0;
				}
            }
        }else{
            /*  チャタリング検出カウント終了し、さらにスイッチの変化がない場合、長押し判定 */
            if (adc_adkey_continue_time > 0) {
                adc_adkey_continue_time--;
                if (adc_adkey_continue_time == 0) {
                    /*  ADキー長押しイベント */
                    adc_adkey_confirm |= ADC_ADKEY_LONG;
                    adc_event_adkey = AdcAdkeyEvtChange;
                }
            }
        }
    }
}

/*****************************************
 VRデコード
*****************************************/
static void adc_decode_vr(AdcChannelType channel)
{
    /*  未変換 */
    adc_vr_value = adc_get_average(channel);
}

/*****************************************
 AD 論理チャネル更新
*****************************************/
static void adc_set_nextch(void)
{
    unsigned char channel;

    channel = adc_channel;
    if (channel == AdcCh0) {
        channel = AdcChMax - 1;
        adc_set_nextbank();
    } else {
        channel--;
    }

    adc_channel = channel;
}

/*****************************************
 バッファバンク ID 更新
*****************************************/
static void adc_set_nextbank(void)
{
    unsigned char bank;

    bank = adc_bank;
    if (bank == (ADC_BANK_SIZE - 1)) {
        bank = 0;
    } else {
        bank++;
    }

    adc_bank = bank;
}

/*****************************************
 論理チャネル別平均値算出
*****************************************/
static unsigned char adc_get_average(AdcChannelType channel)
{
    unsigned char bank;
    unsigned short sum;

    sum = 0;
    for (bank = 0; bank < ADC_BANK_SIZE; bank++) {
        sum += adc_buffer[channel][bank];
    }
    sum /= ADC_BANK_SIZE;

    return ((unsigned char)sum);
}

/********************************************************
 トグル入力 デバイスドライバ
 *******************************************************/
#include <avr/io.h>
#include "input_toggle.h"

/*****************************************
　define
*****************************************/
#define TOGGLE_PORT_DATA_REG            PINC
#define TOGGLE_PORT_PULLUP_REG          PORTC
#define TOGGLE_PORT_DDR_REG             DDRC

#define TOGGLE_BIT                      (0b00001111)    /* 1：トグル使用ポート */

#define TOGGLE_CHATTERING_COUNT         (0)             /*  チャタリング除去判定回数(0：チャタリング除去しない) */

#define TOGGLE_TRUE                     (1)
#define TOGGLE_FALSE                    (0)

/*****************************************
 関数プロトタイプ宣言
*****************************************/
/*  Key input driver (low level) */
static ToggleBitType toggle_input_from_port(void);

/*****************************************
 変数定義
*****************************************/
static ToggleBitType toggle_event = TOGGLE_BIT_NONE;  /* 外部公開用トグルイベント  0 : キー変化なし / 1 : キー変化あり */
static ToggleBitType toggle_state = TOGGLE_BIT_NONE;  /* 外部公開用トグルコード    0 : オフ / 1 : オン */

static ToggleBitType toggle_state_pending;            /* トグルキー チャタリング除去中情報 */
static unsigned char toggle_pending_count;            /* トグルキー チャタリング除去カウント */
static unsigned char toggle_first_boot;               /* 起動後初回である */

/*****************************************
 トグル初期化
*****************************************/
void toggle_init(void)
{
    TOGGLE_PORT_DDR_REG &= (~TOGGLE_BIT); /* トグル用ポートを入力(0)に設定 */
    TOGGLE_PORT_PULLUP_REG |= TOGGLE_BIT; /* トグル用ポートをプルアップあり(1)に設定 */

    toggle_event = TOGGLE_BIT_NONE;
    toggle_state = TOGGLE_BIT_NONE;
    toggle_state_pending = TOGGLE_BIT_NONE;
    toggle_pending_count = 0;
    toggle_first_boot = TOGGLE_TRUE;
}

/*****************************************
 トグル状態チェック処理
*****************************************/
void toggle_scan(void)
{
    unsigned char count;
    ToggleBitType state_latest;

    /* 入力ポート情報を読み込んでトグルキービットを抜き出す */
    state_latest = toggle_input_from_port();

    if (toggle_first_boot != TOGGLE_FALSE) {
        /* ブート後初回は全トグルを変化ありとする */
        toggle_first_boot = TOGGLE_FALSE;
        toggle_event = TOGGLE_BIT;
        toggle_state = state_latest;
        toggle_state_pending = state_latest;
    } else {
        /* チャタリング除去処理 */
        /* キー変化なしのまま規定時間経過したらキーの状態を確定する */
        if (toggle_state_pending != state_latest) {     /* キー変化あり */
            /* チャタリング除去処理開始 */
            toggle_state_pending = state_latest;
            count = TOGGLE_CHATTERING_COUNT;
            toggle_pending_count = TOGGLE_CHATTERING_COUNT;
        } else{                                                                     /* キー変化なし */
            count = toggle_pending_count;
            if (count > 0) { /* チャタリング除去中 */
                /* チャタリング除去カウンタを更新 */
                count--;
                toggle_pending_count = count;
            }
        }
        if (count == 0) { /* チャタリング除去カウント終了 */
            /*  確定値保存 */
            toggle_event |= toggle_state ^ toggle_state_pending;

            toggle_state = toggle_state_pending;
        }
    }
}

/*****************************************
 トグル変化情報取得
*****************************************/
ToggleBitType toggle_check_event(void)
{
    return toggle_event;
}

/*****************************************
 トグル変化イベント有無情報クリア
*****************************************/
void toggle_clear_event(void)
{
    toggle_event = TOGGLE_BIT_NONE;
}

/*****************************************
 トグル状態取得
*****************************************/
ToggleBitType toggle_get_state(void)
{
    return toggle_state;
}

/*****************************************
 トグルキー情報をポートから取得
*****************************************/
static ToggleBitType toggle_input_from_port(void)
{
    return (TOGGLE_PORT_DATA_REG & TOGGLE_BIT);
}

/********************************************************
 LCD デバイスドライバ
 *******************************************************/
#include <avr/io.h>
#include "output_lcd.h"

/*****************************************
 マクロ定数
*****************************************/
/* ポート設定 */
#define LCD_PORT_DATA_REG   PORTD
#define LCD_PORT_DDR_REG    DDRD
#define LCD_PORT_RS_BIT     (0b00010000)
#define LCD_PORT_E_BIT      (0b00100000)
#define LCD_PORT_DATA_BIT   (0b00001111)
#define LCD_PORT_ALL_BIT    (LCD_PORT_RS_BIT | LCD_PORT_E_BIT | LCD_PORT_DATA_BIT)

/* LCDバッファサイズ設定 */
#define LCD_ROW_SIZE        (2)
#define LCD_COL_SIZE        (16)
#define LCD_BUF_SIZE        (LCD_ROW_SIZE * LCD_COL_SIZE)

/* 待ち時間設定 */
#define LCD_BOOT_WAIT       (50) /* 電源ON時初回コマンド送信待ち時間[ms] */
#define LCD_INIT_CMD_WAIT   (4)  /* 初期化コマンド反映待ち時間[ms] */

/* 初期化シーケンス番号 */
#define LCD_INIT_SEQ_0          (0)
#define LCD_INIT_SEQ_1          (1)
#define LCD_INIT_SEQ_2          (2)
#define LCD_INIT_SEQ_3          (3)
#define LCD_INIT_SEQ_4          (4)
#define LCD_INIT_SEQ_5          (5)
#define LCD_INIT_SEQ_6          (6)
#define LCD_INIT_SEQ_7          (7)

#define LCD_INIT_SEQ_COMPLETE   (LCD_INIT_SEQ_7)

/*****************************************
 型
*****************************************/
/* LCD表示状態 */
typedef enum {
    LcdStateOff,     /*  LCDオフ */
    LcdStateOn       /*  LCDオン */
} LcdStateType;


/*****************************************
 関数
*****************************************/
static void lcd_put_num(unsigned short value, unsigned char digit, unsigned char zero_padding);
static void lcd_disp_on(void);
static void lcd_disp_off(void);
static unsigned char lcd_check_buffer_diff(void);
static void lcd_output_string(const unsigned char* str, unsigned char row);      /*  output String Data */
static void lcd_output_char(unsigned char data, unsigned char row, unsigned char col);   /*  output Char Data */
static void lcd_out_init_command(unsigned char);       /* LCD initial setting command output */
static void lcd_out_command8bit(unsigned char);        /* LCD 1 command output */
static void lcd_out_data8bit(unsigned char);           /* LCD 1 date output */
static void lcd_out_lcd4bit(unsigned char outdata);    /* LCD データポート出力 */
static void lcd_out_rs_to_data(void);
static void lcd_out_rs_to_cmd(void);
static void lcd_wait_us(unsigned short us);

/*****************************************
 変数
*****************************************/
static LcdStateType lcd_state;              /* LCD表示状態 */
static LcdStateType lcd_state_pending;      /* LCD表示状態(反映前) */
static unsigned char lcd_init_seq_cnt;      /* 現在の初期化シーケンス番号 */
static unsigned char lcd_init_cmd_wait_cnt; /* 初期化用待ち時間カウンタ */
static unsigned char lcd_input_cursor;      /* カーソル位置(バッファ書き込み用) */
static unsigned char lcd_output_cursor;     /* カーソル位置(LCD出力用) */
static unsigned char lcd_disp_updating;     /* 表示更新処理中フラグ */

/* 表示データの一時保存用バッファ */
static char lcd_buf_pending[LCD_ROW_SIZE][LCD_COL_SIZE];
/* 表示用データバッファ */
static char lcd_buf[LCD_ROW_SIZE][LCD_COL_SIZE];

/* サンプル表示用文字列定数 */
static const unsigned char lcd_sample_data[LCD_ROW_SIZE][LCD_COL_SIZE] = {
    {' ','W','e','l','c','o','m','e','!','!',' ',' ',' ',' ',' ',' '},
    {' ','a','r','d','u','i','n','o',' ','s','a','m','p','l','e',' '}
};

/* 行ごとのLCD表示先頭アドレス */
static const unsigned char lcd_row_offset_address[LCD_ROW_SIZE] = {
    0x80,
    0xc0
};

/*****************************************
 LCD初期設定
*****************************************/
void lcd_init( void )
{
    unsigned char row;
    unsigned char col;

    /* ポート(LCD)初期設定 */
    LCD_PORT_DDR_REG |= LCD_PORT_ALL_BIT;
    LCD_PORT_DATA_REG &= (~LCD_PORT_ALL_BIT);

    lcd_state = LcdStateOff;
    lcd_state_pending = LcdStateOn; /* 初期化完了時の状態を想定してONを入れておき、初期化途中でもOFF要求を受け付けられるようにする */
    lcd_input_cursor = 0;
    lcd_output_cursor = 0;
    lcd_disp_updating = LCD_FALSE;

    for (row = 0; row < LCD_ROW_SIZE; row++) {
        for (col = 0; col < LCD_COL_SIZE; col++) {
            lcd_buf[row][col] = ' ';
            lcd_buf_pending[row][col] = ' ';
        }
    }

    lcd_init_seq_cnt = LCD_INIT_SEQ_0;
    lcd_init_cmd_wait_cnt = LCD_BOOT_WAIT;
}

/*****************************************
 初期化シーケンス実施
*****************************************/
LcdInitStateType lcd_init_seq(void)
{
    LcdInitStateType init_state;
    unsigned char init_seq_cnt;

    init_state = LcdInitWait;

    init_seq_cnt = lcd_init_seq_cnt;
    switch (init_seq_cnt) {
        case LCD_INIT_SEQ_0:
            /* 電源ON～コマンド送信前ウエイト */
            lcd_init_cmd_wait_cnt--;
            if(lcd_init_cmd_wait_cnt == 0){
                init_seq_cnt = LCD_INIT_SEQ_1;
            }
            break;

        case LCD_INIT_SEQ_1:
            lcd_out_init_command(0x03);         /* LCDファンクションセット */
            init_seq_cnt = LCD_INIT_SEQ_2;
            lcd_init_cmd_wait_cnt = LCD_INIT_CMD_WAIT;
            break;

        case LCD_INIT_SEQ_2:
            /* 4.1msウエイト */
            lcd_init_cmd_wait_cnt--;
            if(lcd_init_cmd_wait_cnt == 0){
                init_seq_cnt = LCD_INIT_SEQ_3;
            }
            break;

        case LCD_INIT_SEQ_3:
            lcd_out_init_command(0x03);         /* LCDファンクションセット */
            lcd_out_init_command(0x03);         /* LCDファンクションセット */
            lcd_out_init_command(0x02);         /* LCDデータを4ビット長に設定 */
            lcd_out_command8bit(0x28);          /* 4bit､2行文､5×7ドットに設定 */
            lcd_out_command8bit(0x08);          /* 表示オフ */
            init_seq_cnt = LCD_INIT_SEQ_4;
            break;

        case LCD_INIT_SEQ_4:
            lcd_out_command8bit(0x01);          /* 表示クリア */
            init_seq_cnt = LCD_INIT_SEQ_5;
            break;

        case LCD_INIT_SEQ_5:
            lcd_out_command8bit(0x06);          /* エントリーモード､インクリメント */
            init_seq_cnt = LCD_INIT_SEQ_6;
            break;

        case LCD_INIT_SEQ_6:
            lcd_state = lcd_state_pending;
            /* LCD表示処理 */
            if (lcd_state == LcdStateOff) {
                lcd_disp_off();
            } else {
                lcd_disp_on();
            }
            init_seq_cnt = LCD_INIT_SEQ_7;
            init_state = LcdInitComplete;
            break;

        case LCD_INIT_SEQ_7:
            init_state = LcdInitComplete;
            break;

        default:
            break;
    }
    lcd_init_seq_cnt = init_seq_cnt;

    return init_state;
}

/*****************************************
 LCDデータ転送 & 表示制御
*****************************************/
void lcd_display( void )
{
    unsigned char row;
    unsigned char col;

    /* 初期化シーケンスが終わっていなければ、表示制御せずに初期化シーケンスの続きを実施 */
    if (lcd_init_seq_cnt != LCD_INIT_SEQ_COMPLETE){
        (void)lcd_init_seq();
        return;
    }

    if (lcd_disp_updating == LCD_FALSE) {
        if (lcd_check_buffer_diff() != LCD_FALSE) {
            lcd_disp_updating = LCD_TRUE;   /* 入力バッファと出力バッファに差異がある場合は */
                                            /* 出力バッファをLCDに転送するための要求フラグをセット */
            lcd_output_cursor = 0;

            /*  入力バッファデータを出力バッファにコピー */
            for (row = 0; row < LCD_ROW_SIZE; row++) {
                for (col = 0; col < LCD_COL_SIZE; col++) {
                    lcd_buf[row][col] = lcd_buf_pending[row][col];
                }
            }
        }else{

        }
    } else {
        col = lcd_output_cursor;
        row = 0;
        while(col >= LCD_COL_SIZE){
            row++;
            col-=LCD_COL_SIZE;
        }

        /* 1文字出力 */
        lcd_output_char(lcd_buf[row][col], row, col);

        lcd_output_cursor++;
        if (lcd_output_cursor == (LCD_COL_SIZE * LCD_ROW_SIZE)) { /* 出力バッファ全体の出力が完了したら */
            lcd_disp_updating = LCD_FALSE;   /* 出力バッファのLCD転送要求フラグをクリア */
        }
    }

    if (lcd_state != lcd_state_pending) {
        /* LCDオン・オフの内部状態を更新 */
        lcd_state = lcd_state_pending;
        /* LCD表示処理 */
        if (lcd_state == LcdStateOff) {
            lcd_disp_off();
        } else {
            lcd_disp_on();
        }
    }
}

